import{_ as e,o as i,c as t,a2 as s}from"./chunks/framework.LN3EJxkW.js";const k=JSON.parse('{"title":"Transformer、Attention、Q/K/V、位置与自回归生成","description":"","frontmatter":{"type":"ai-note","stage":"beginner","topic":"transformer-attention-generation","verified":"2026-07-17T00:00:00.000Z","tags":["ai","transformer","attention","qkv","positional-encoding","autoregressive"]},"headers":[],"relativePath":"04-ai/notes/00-foundations/transformer-attention-generation.md","filePath":"04-ai/notes/00-foundations/transformer-attention-generation.md","lastUpdated":1784542968000}'),n={name:"04-ai/notes/00-foundations/transformer-attention-generation.md"};function l(r,a,o,d,h,p){return i(),t("div",null,[...a[0]||(a[0]=[s(`<h1 id="transformer、attention、q-k-v、位置与自回归生成" tabindex="-1">Transformer、Attention、Q/K/V、位置与自回归生成 <a class="header-anchor" href="#transformer、attention、q-k-v、位置与自回归生成" aria-label="Permalink to &quot;Transformer、Attention、Q/K/V、位置与自回归生成&quot;">​</a></h1><h2 id="_1-概念、用途与工程边界" tabindex="-1">1. 概念、用途与工程边界 <a class="header-anchor" href="#_1-概念、用途与工程边界" aria-label="Permalink to &quot;1. 概念、用途与工程边界&quot;">​</a></h2><h3 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h3><p>Transformer 是以 Attention 和前馈网络为核心的序列模型架构。Self-Attention 让序列中每个位置根据其他可见位置计算加权信息。输入表示通过不同线性投影生成 Query、Key 和 Value：Query 与 Key 决定权重，权重再聚合 Value。位置信息用于区分 Token 顺序。自回归语言模型按条件概率一次生成下一个 Token，并把已生成 Token 作为后续上下文。</p><h3 id="为什么需要" tabindex="-1">为什么需要 <a class="header-anchor" href="#为什么需要" aria-label="Permalink to &quot;为什么需要&quot;">​</a></h3><p>这些机制解释了模型为何受上下文、顺序、Token 数和解码策略影响，也解释了生成输出为何不是直接查询事实表。应用工程不需要从零训练 Transformer，但需要理解上下文限制和生成误差来源。</p><h3 id="核心特性" tabindex="-1">核心特性 <a class="header-anchor" href="#核心特性" aria-label="Permalink to &quot;核心特性&quot;">​</a></h3><p>Scaled dot-product Attention 的核心形式：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Attention(Q,K,V) = softmax(QKᵀ / √dₖ)V</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ul><li>Self-Attention 的 Q/K/V 来自同一序列的不同投影。</li><li>Multi-head Attention 使用多组投影并行计算，再合并结果。</li><li>因果 Mask 阻止自回归模型在训练/生成某位置时查看未来 Token。</li><li>原始 Transformer 使用正弦/余弦位置编码；现代模型也使用可学习、旋转或其他位置方法，具体取决于模型。</li><li>自回归生成在每一步产生下一 Token 分布，再按贪心、采样或搜索策略选择 Token。</li><li>Attention 权重不是可靠的自然语言解释或事实依据。</li></ul><h3 id="工程使用" tabindex="-1">工程使用 <a class="header-anchor" href="#工程使用" aria-label="Permalink to &quot;工程使用&quot;">​</a></h3><p>应用层面的直接影响：</p><ol><li>指令、数据和示例的顺序会影响可见上下文和注意分配，需通过评测确认。</li><li>长文本要保留结构、来源和相关片段，不能仅靠一次塞满窗口。</li><li>Streaming 展示逐 Token/事件生成结果，但中间内容可能被后续内容修正。</li><li>温度和采样控制输出分布，不修复缺失知识、错误上下文和权限问题。</li><li>要求事实可靠时使用检索、工具、引用和校验，不把语言流畅度当作真实性。</li></ol><h3 id="常见错误与边界" tabindex="-1">常见错误与边界 <a class="header-anchor" href="#常见错误与边界" aria-label="Permalink to &quot;常见错误与边界&quot;">​</a></h3><ul><li>把 Attention 解释为模型“理解”或可直接读取的推理过程。</li><li>认为模型逐字从训练数据复制；生成基于参数化概率分布，仍可能记忆或复现训练片段，但机制不能简单等同数据库检索。</li><li>认为更大 Context Window 自动解决长期记忆和事实更新。</li><li>用温度 <code>0</code> 承诺完全确定和永远正确。</li><li>把 Q/K/V 当作固定的人类可读“问题、键、答案”；它们是学习得到的向量投影。</li></ul><h3 id="延伸机制" tabindex="-1">延伸机制 <a class="header-anchor" href="#延伸机制" aria-label="Permalink to &quot;延伸机制&quot;">​</a></h3><p>推理时 KV Cache 保存先前 Token 的 Key/Value，减少重复计算，但占用显存并影响长上下文服务成本。不同模型可能采用稀疏、滑动窗口或其他 Attention 变体。</p><h2 id="单个自回归步骤" tabindex="-1">单个自回归步骤 <a class="header-anchor" href="#单个自回归步骤" aria-label="Permalink to &quot;单个自回归步骤&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[&quot;Token 与位置表示&quot;] --&gt; B[&quot;多层 Attention + 前馈网络&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[&quot;下一 Token logits&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[&quot;解码策略&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; E[&quot;选定下一 Token&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; A</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>每一步输出的是词表上的数值分布；解码策略选择 Token，再把它加入后续输入。模型不会在生成开始时先固定整段自然语言答案。</p><h2 id="q、k、v-与生成参数" tabindex="-1">Q、K、V 与生成参数 <a class="header-anchor" href="#q、k、v-与生成参数" aria-label="Permalink to &quot;Q、K、V 与生成参数&quot;">​</a></h2><table tabindex="0"><thead><tr><th>名称</th><th>作用</th><th>不能推出</th></tr></thead><tbody><tr><td>Query</td><td>当前位置用于匹配的信息表示</td><td>人类可读问题</td></tr><tr><td>Key</td><td>被匹配位置的索引表示</td><td>数据库主键</td></tr><tr><td>Value</td><td>按权重聚合的内容表示</td><td>事实答案</td></tr><tr><td>因果 Mask</td><td>禁止看到未来位置</td><td>输出事实正确</td></tr><tr><td>Temperature</td><td>缩放 logits 后影响分布</td><td>修复知识和权限缺失</td></tr><tr><td>KV Cache</td><td>复用先前位置的 K/V 计算</td><td>无限长期记忆</td></tr></tbody></table><h2 id="可计算示例" tabindex="-1">可计算示例 <a class="header-anchor" href="#可计算示例" aria-label="Permalink to &quot;可计算示例&quot;">​</a></h2><p>若两个候选 Token 的 logits 为 <code>[2, 1]</code>，softmax 概率约为 <code>[0.731, 0.269]</code>。Temperature 为 2 时先变成 <code>[1, 0.5]</code>，概率约为 <code>[0.622, 0.378]</code>，分布更平；Temperature 为 0.5 时变成 <code>[4, 2]</code>，概率约为 <code>[0.881, 0.119]</code>，分布更尖。具体 API 是否支持 Temperature 及其范围由模型供应商决定。</p><h2 id="验证与排错" tabindex="-1">验证与排错 <a class="header-anchor" href="#验证与排错" aria-label="Permalink to &quot;验证与排错&quot;">​</a></h2><ol><li>区分模型架构事实、供应商服务参数和应用约定。</li><li>对同一输入记录完整模型 ID、解码参数和多次 Trial。</li><li>长上下文退化时检查相关片段位置、干扰信息和截断，不只增加窗口。</li><li>事实任务使用检索、工具和引用验证，不能用 Attention 权重证明答案依据。</li></ol><h2 id="练习与完成标准" tabindex="-1">练习与完成标准 <a class="header-anchor" href="#练习与完成标准" aria-label="Permalink to &quot;练习与完成标准&quot;">​</a></h2><p>手算两个 logits 在 Temperature 1 和 2 下的 softmax，并说明概率变化。验收：正确解释 Q/K/V、因果 Mask、自回归和 KV Cache；明确 Temperature 不保证正确性；给出一个用外部证据验证事实输出的流程。</p><h2 id="完整案例-从上下文到下一个-token" tabindex="-1">完整案例：从上下文到下一个 Token <a class="header-anchor" href="#完整案例-从上下文到下一个-token" aria-label="Permalink to &quot;完整案例：从上下文到下一个 Token&quot;">​</a></h2><h3 id="输入" tabindex="-1">输入 <a class="header-anchor" href="#输入" aria-label="Permalink to &quot;输入&quot;">​</a></h3><p>假设词表只含 <code>A</code>、<code>B</code>、<code>C</code>，当前步骤得到 logits <code>[2.0, 1.0, 0.0]</code>。该简化输入只展示解码，不代表真实模型词表、隐藏层或供应商采样实现。</p><h3 id="逐步处理" tabindex="-1">逐步处理 <a class="header-anchor" href="#逐步处理" aria-label="Permalink to &quot;逐步处理&quot;">​</a></h3><ol><li>当前 Token 表示加入位置信息后进入 Transformer 层。</li><li>每个 Attention Head 计算 Q 与 K 的缩放点积、应用因果 Mask、经过 softmax 后聚合 V。</li><li>多头结果与前馈网络产生当前位置隐藏表示，输出投影得到 logits。</li><li>Temperature 为 1 时，softmax 概率约为 <code>[0.665, 0.245, 0.090]</code>。</li><li>若使用贪心选择，下一 Token 为 <code>A</code>；若使用随机采样，<code>B</code> 和 <code>C</code> 仍可能被选中。</li><li>选中的 Token 加入上下文，下一步复用可用的 KV Cache 并再次计算分布。</li></ol><h3 id="输出" tabindex="-1">输出 <a class="header-anchor" href="#输出" aria-label="Permalink to &quot;输出&quot;">​</a></h3><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;logits&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;temperature&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1.0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;probabilities&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.665</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.245</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0.09</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">],</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;greedy_next_token&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;A&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><h3 id="验证" tabindex="-1">验证 <a class="header-anchor" href="#验证" aria-label="Permalink to &quot;验证&quot;">​</a></h3><ul><li>三个概率之和在浮点容差内等于 1。</li><li>Temperature 降低后分布变尖，提高后分布变平。</li><li>因果 Mask 的未来位置权重在 softmax 后为 0。</li><li>重复 API 调用是否确定由具体模型与服务实现决定，不能从 Temperature 单独推断。</li></ul><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>即使贪心选择每步最高概率 Token，完整回答也可能事实错误，因为概率来自模型参数和上下文，不是事实数据库。事实任务需要检索或 Tool 提供证据，并由应用校验引用与业务规则。Attention 权重也不能证明模型使用了哪条事实依据。</p><h2 id="边界检查矩阵" tabindex="-1">边界检查矩阵 <a class="header-anchor" href="#边界检查矩阵" aria-label="Permalink to &quot;边界检查矩阵&quot;">​</a></h2><ol><li>Token 表示与人类单词边界不一定一致。</li><li>位置信息方案由具体模型架构定义。</li><li>Q/K/V 是学习投影，不是可读语义标签。</li><li>缩放项 <code>√dₖ</code> 控制点积数值尺度。</li><li>softmax 把可见位置分数转为归一化权重。</li><li>因果 Mask 阻止访问未来 Token。</li><li>Multi-head 使用多组投影后合并。</li><li>前馈网络在各位置独立应用共享参数。</li><li>logits 经过解码策略才产生下一个 Token。</li><li>KV Cache 减少重复计算但增加内存占用。</li><li>采样参数支持范围与默认值由 API 定义。</li><li>生成概率不能替代事实、权限或业务验证。</li></ol><h2 id="attention-计算中的形状与-mask" tabindex="-1">Attention 计算中的形状与 Mask <a class="header-anchor" href="#attention-计算中的形状与-mask" aria-label="Permalink to &quot;Attention 计算中的形状与 Mask&quot;">​</a></h2><p>设单个 Head 的序列长度为 <code>n</code>，Key 维度为 <code>dₖ</code>，则 Q 和 K 可表示为 <code>n × dₖ</code>，<code>QKᵀ</code> 得到 <code>n × n</code> 的位置间分数矩阵。除以 <code>√dₖ</code> 后应用 Mask，再沿可见 Key 维度做 softmax。与 V 相乘后，每个位置得到加权表示。真实实现会批处理、多头并行并采用数值稳定优化，但数学对象的角色不变。</p><p>Padding Mask 与因果 Mask 解决不同问题：Padding Mask 排除补齐位置，因果 Mask 排除未来位置。是否需要、如何组合取决于架构和任务。把 Mask 写错会让训练看到不应看到的 Token，或让有效输入无法参与计算；应用开发者通常不直接设置底层 Mask，但在阅读模型架构和排查上下文行为时应区分。</p><p>自回归生成的停止还受结束 Token、输出上限、停止序列、工具调用和服务策略影响。具体字段、默认值和可用范围属于模型 API 契约。应用应记录完成状态和停止原因，不能把网络连接结束等同于模型正常生成结束。</p><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://arxiv.org/abs/1706.03762" target="_blank" rel="noreferrer">Vaswani et al.：Attention Is All You Need</a>（访问日期：2026-07-17）</li><li><a href="https://docs.pytorch.org/docs/stable/generated/torch.nn.functional.scaled_dot_product_attention.html" target="_blank" rel="noreferrer">PyTorch：Scaled Dot Product Attention</a>（访问日期：2026-07-17）</li><li><a href="https://huggingface.co/learn/llm-course/en/chapter1/4" target="_blank" rel="noreferrer">Hugging Face LLM Course</a>（访问日期：2026-07-17）</li><li><a href="https://developers.google.com/machine-learning/resources/intro-llms" target="_blank" rel="noreferrer">Google：Introduction to Large Language Models</a>（访问日期：2026-07-17）</li></ul>`,47)])])}const u=e(n,[["render",l]]);export{k as __pageData,u as default};
